Exit fullscreen mode

import axios from "axios"
const r = await axios.get("https://api.example.com/users/42", { timeout: 5000 })
if (r.status === 200) {
console.log(r.data)
} else if (r.status === 404) {
console.log("not found")
} else {
throw new Error(`unexpected status: ${r.status}`)
}

